  // pragma quickuvm custom sequences_additional begin
  // The directed register program — the smoke recipe, as a sequence. A sequence ITEM has
  // no `start()`; only a sequence can call start_item/finish_item, so it lives here at
  // package scope rather than in the test.
  class regbus_prog_seq extends uvm_sequence #(regbus_item);
    `uvm_object_utils(regbus_prog_seq)

    localparam bit [5:0] RControl    = 6'h10;
    localparam bit [5:0] RConfigopts = 6'h18;
    localparam bit [5:0] RCommand    = 6'h20;
    localparam bit [5:0] RRxdata     = 6'h24;
    localparam bit [5:0] RTxdata     = 6'h28;

    function new(string name = "regbus_prog_seq");
      super.new(name);
    endfunction

    task automatic beat(bit [5:0] a, bit wrn, bit [31:0] d, bit [3:0] ben = 4'hf);
      regbus_item it;
      it = regbus_item::type_id::create("it");
      start_item(it);
      it.addr  = a;
      it.wr    = wrn;
      it.wdata = d;
      it.be    = ben;
      it.req   = 1'b1;
      finish_item(it);
    endtask

    task body;
      int unsigned cpol = 0, cpha = 0, speed = 0;
      void'($value$plusargs("SPI_CPOL=%d", cpol));
      void'($value$plusargs("SPI_CPHA=%d", cpha));
      void'($value$plusargs("SPI_SPEED=%d", speed));   // 0=Std, 1=Dual, 2=Quad

      // CONTROL.OUTPUT_EN (bit 29) is NOT optional. It resets to 0 and gates sck, csb and
      // every sd lane: without it the DUT drives NOTHING, the pull-ups float the bus high,
      // and the bench passes by doing nothing. That is mutation M1.
      beat(RControl,    1'b1, (32'h1 << 31) | (32'h1 << 29) | 32'h7f);
      // CPOL[31], CPHA[30], csn lead/trail/idle, clkdiv
      beat(RConfigopts, 1'b1, (32'(cpol) << 31) | (32'(cpha) << 30) |
                              (32'd2 << 24) | (32'd2 << 20) | (32'd2 << 16) | 32'd4);

      for (int f = 0; f < 8; f++) begin
        if (speed == 0) begin
          // Standard, Bidir: push a TX byte and read one back, full duplex.
          beat(RTxdata,  1'b1, {24'h0, 8'h5A ^ 8'(f)}, 4'b0001);
          beat(RCommand, 1'b1, (32'd3 << 23) | 32'd0);          // direction=Bidir, Standard
        end else begin
          // Dual/Quad, RdOnly: no TX — the device provides the data on the shared lanes.
          // direction=RdOnly (bit 23), speed in [22:21], len=0 => one byte.
          beat(RCommand, 1'b1, (32'd1 << 23) | (32'(speed) << 21) | 32'd0);
        end
        #3000ns;                                        // let the frame run
        beat(RRxdata,  1'b0, '0);                       // pop what the device sent us
        #200ns;
      end
      #500ns;
    endtask
  endclass
